def findDiagonalOrder(mat):
    if not mat: return []
    m, n = len(mat), len(mat[0]); res = []; d = collections.defaultdict(list)
    for r in range(m):
        for c in range(n): d[r+c].append(mat[r][c])
    for k in range(m+n-1):
        if k % 2 == 0: res.extend(d[k][::-1])
        else: res.extend(d[k])
    return res

